// services/announcements.service.ts
import { Injectable, inject } from '@angular/core';
import { Observable, from, of } from 'rxjs';
import { map, catchError, first } from 'rxjs/operators';
import { BaseService } from './base.service';
import { Announcement, AnnouncementRead } from '../models';
import { AuthService } from './timbrature-auth.adapter';

@Injectable({ providedIn: 'root' })
export class AnnouncementsService extends BaseService<Announcement> {
  protected override tableName = 'announcements';

  private authService = inject(AuthService);

  /**
   * Ottiene tutti gli annunci di un'azienda, ordinati per data decrescente.
   */
  getAnnunciAzienda(companyId: string): Observable<Announcement[]> {
    if (!companyId) return of([]);
    return from(
      this.supabase
        .from(this.tableName)
        .select('*')
        .eq('company_id', companyId)
        .order('created_at', { ascending: false })
    ).pipe(
      map(result => result.data as Announcement[]),
      catchError(error => {
        console.error('[AnnouncementsService] getAnnunciAzienda error', error);
        throw error;
      })
    );
  }

  /**
   * Restituisce gli annunci dell'azienda con il flag is_read per l'utente corrente.
   */
  getAnnunciAziendaWithReadStatus(companyId: string): Observable<(Announcement & { is_read: boolean })[]> {
    if (!companyId) return of([]);
    const promise = (async () => {
      const currentUser = await this.authService.currentUser$.pipe(first()).toPromise();
      if (!currentUser) return [];

      const { data: announcements, error: annErr } = await this.supabase
        .from(this.tableName)
        .select('*')
        .eq('company_id', companyId)
        .order('created_at', { ascending: false });

      if (annErr) throw annErr;
      const annList = (announcements || []) as Announcement[];

      if (annList.length === 0) return [];

      const ids = annList.map(a => a.id).filter((id): id is string => !!id);
      const { data: reads, error: readsErr } = await this.supabase
        .from('announcements_reads')
        .select('announcement_id')
        .in('announcement_id', ids)
        .eq('user_id', currentUser.id);

      if (readsErr) throw readsErr;

      const readSet = new Set((reads || []).map(r => r.announcement_id));
      return annList.map(a => ({ ...a, is_read: readSet.has(a.id) }));
    })();

    return from(promise);
  }

  /**
   * Crea un nuovo annuncio (solo admin). Il metodo verifica il ruolo tramite AuthService.
   */
  creaAnnuncio(companyId: string, annuncio: { title: string; content: string; author_id: string }): Observable<Announcement> {
    const promise = (async () => {
      const currentUser = await this.authService.currentUser$.pipe(first()).toPromise();
      if (!currentUser || !this.authService.hasRole('admin')) {
        throw new Error('Solo gli admin possono creare annunci');
      }

      const payload = {
        company_id: companyId,
        title: annuncio.title,
        content: annuncio.content,
        created_by: annuncio.author_id || currentUser.id,
        created_at: new Date().toISOString(),
        is_active: true
      };

      const { data, error } = await this.supabase
        .from(this.tableName)
        .insert(payload)
        .select()
        .single();

      if (error) throw error;
      return data as Announcement;
    })();

    return from(promise);
  }

  /**
   * Marca un annuncio come letto per l'utente corrente (upsert).
   */
  markAsRead(announcementId: string): Observable<AnnouncementRead | null> {
    if (!announcementId) return of(null);
    const promise = (async () => {
      const currentUser = await this.authService.currentUser$.pipe(first()).toPromise();
      if (!currentUser) throw new Error('Utente non autenticato');

      const payload = {
        announcement_id: announcementId,
        user_id: currentUser.id,
        read_at: new Date().toISOString()
      };

      const { data, error } = await this.supabase
        .from('announcements_reads')
        .upsert(payload, { onConflict: 'announcement_id, user_id' })
        .select()
        .single();

      if (error) throw error;
      return data as AnnouncementRead;
    })();
    return from(promise);
  }

  /**
   * Rimuove la lettura (segna come non letto).
   */
  markAsUnread(announcementId: string): Observable<boolean> {
    if (!announcementId) return of(false);
    const promise = (async () => {
      const currentUser = await this.authService.currentUser$.pipe(first()).toPromise();
      if (!currentUser) throw new Error('Utente non autenticato');

      const { error } = await this.supabase
        .from('announcements_reads')
        .delete()
        .eq('announcement_id', announcementId)
        .eq('user_id', currentUser.id);

      if (error) throw error;
      return true;
    })();
    return from(promise);
  }

  /**
   * Restituisce il numero di annunci non letti per l'utente nell'azienda.
   */
  getUnreadCountForUser(companyId: string): Observable<number> {
    const promise = (async () => {
      if (!companyId) return 0;
      const currentUser = await this.authService.currentUser$.pipe(first()).toPromise();
      if (!currentUser) return 0;

      const { data: annData, error: annErr } = await this.supabase
        .from(this.tableName)
        .select('id')
        .eq('company_id', companyId)
        .eq('is_active', true);

      if (annErr) throw annErr;
      const ids = (annData || []).map(a => a.id);
      if (ids.length === 0) return 0;

      const { data: readsData, error: readsErr } = await this.supabase
        .from('announcements_reads')
        .select('announcement_id')
        .in('announcement_id', ids)
        .eq('user_id', currentUser.id);

      if (readsErr) throw readsErr;
      const readIds = new Set((readsData || []).map(r => r.announcement_id));
      return ids.filter(id => !readIds.has(id)).length;
    })();

    return from(promise);
  }
}
