import { Component, ElementRef, OnInit, OnDestroy, ViewChild, inject } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { Subject, lastValueFrom, takeUntil } from 'rxjs';

import { AuthService } from '../../services/timbrature-auth.adapter';
import { UsersService } from '../../services/user.service';
import { CompanyService } from '../../services/company.service';
import { TimbratureService } from '../../services/timbrature.service';

import { Company, User, AnnouncementWithReadStatus } from '../../models';
import { LUCIDE_ICONS, LucideAngularModule } from 'lucide-angular';
import { AnnouncementsService } from '../../services/announcements.service';

interface StatisticheAzienda {
  dipendentiTotali: number;
  dipendentiAttivi: number;
  timbratureOggi: number;
  presenzeOggi: number;
}

@Component({
  selector: 'app-profilo-aziendale',
  standalone: true,
  imports: [CommonModule, FormsModule, LucideAngularModule],
  templateUrl: './profilo-aziendale.component.html',
  styleUrls: ['./profilo-aziendale.component.css']
})
export class ProfiloAziendaleComponent implements OnInit, OnDestroy {
  @ViewChild('announcementsSection') announcementsSectionRef?: ElementRef<HTMLElement>;

  private authService = inject(AuthService);
  private usersService = inject(UsersService);
  private companyService = inject(CompanyService);
  private timbratureService = inject(TimbratureService);
  private announcementsService = inject(AnnouncementsService);

  currentUser: User | null = null;
  azienda: Company | null = null;
  adminAzienda: User | null = null;
  dipendenti: User[] = [];
  statistiche: StatisticheAzienda | null = null;
  annunci: AnnouncementWithReadStatus[] = [];
  selectedAnnouncement: AnnouncementWithReadStatus | null = null;

  isLoading = true;
  isLoadingAnnunci = false;

  // UI per annunci
  mostraFormAnnuncio = false;
  nuovoAnnuncio = { title: '', content: '' };
  showAnnouncementModal = false;
  modalStyle: { [k: string]: string } = {};

  // Giorni settimana per orari
  giorniSettimana = [
    { key: 'monday', label: 'Lunedì' },
    { key: 'tuesday', label: 'Martedì' },
    { key: 'wednesday', label: 'Mercoledì' },
    { key: 'thursday', label: 'Giovedì' },
    { key: 'friday', label: 'Venerdì' },
    { key: 'saturday', label: 'Sabato' },
    { key: 'sunday', label: 'Domenica' }
  ];

  private destroy$ = new Subject<void>();

ngOnInit() {
  this.authService.currentUser$
    .pipe(takeUntil(this.destroy$))
    .subscribe(user => {
      this.currentUser = user as any;
      const companyId = this.authService.companyId;
      if (companyId) {
        this.loadCompanyData(companyId);
      } else {
        this.resetData();
      }
    });
}

  ngOnDestroy() {
    this.destroy$.next();
    this.destroy$.complete();
  }

  private resetData() {
    this.azienda = null;
    this.adminAzienda = null;
    this.dipendenti = [];
    this.statistiche = null;
    this.annunci = [];
  }

  private async loadCompanyData(companyId: string) {
    this.isLoading = true;
    try {
      // Carica azienda
      this.azienda = await lastValueFrom(this.companyService.getById(companyId));

      // Carica dipendenti
      this.dipendenti = await lastValueFrom(this.usersService.getByCompany(companyId));

      // Trova admin
      this.adminAzienda = this.dipendenti.find(d => (d.role as any) === 'admin') || null;

      // Statistiche base dipendenti
      this.statistiche = {
        dipendentiTotali: this.dipendenti.length,
        dipendentiAttivi: this.dipendenti.filter(d => d.is_active).length,
        timbratureOggi: 0,
        presenzeOggi: 0
      };

      // Carica timbrature di oggi
      await this.loadTimbratureOggi(companyId);

      // Carica annunci
      await this.loadAnnunci(companyId);
    } catch (error) {
      console.error('Errore caricamento dati azienda', error);
    } finally {
      this.isLoading = false;
    }
  }

  private async loadTimbratureOggi(companyId: string) {
    try {
      const oggi = new Date();
      oggi.setHours(0, 0, 0, 0);
      const domani = new Date(oggi);
      domani.setDate(domani.getDate() + 1);

      const timbrature = await lastValueFrom(
        this.timbratureService.getFiltered({
          company_id: companyId,
          start_ts: {
            gte: oggi.toISOString(),
            lt: domani.toISOString()
          }
        })
      );

      if (this.statistiche) {
        this.statistiche.timbratureOggi = timbrature.length;
        this.statistiche.presenzeOggi = new Set(timbrature.map(t => t.user_id)).size;
      }
    } catch (error) {
      console.error('Errore caricamento timbrature oggi', error);
      if (this.statistiche) {
        this.statistiche.timbratureOggi = 0;
        this.statistiche.presenzeOggi = 0;
      }
    }
  }

  private async loadAnnunci(companyId: string) {
    this.isLoadingAnnunci = true;
    try {
      this.annunci = await lastValueFrom(
        this.announcementsService.getAnnunciAziendaWithReadStatus(companyId)
      );
    } catch (error) {
      console.error('Errore caricamento annunci', error);
      this.annunci = [];
    } finally {
      this.isLoadingAnnunci = false;
    }
  }


  // --- Gestione annunci ---
  async openAnnouncement(ann: AnnouncementWithReadStatus) {
    await this.ensureSectionVisible();

    const el = this.announcementsSectionRef?.nativeElement;
    const rect = el ? el.getBoundingClientRect() : null;
    const viewportPad = 20;
    const popupMaxWidth = 900;
    const sectionLeft = rect ? rect.left + window.scrollX : window.scrollX + viewportPad;
    const sectionTop = rect ? rect.top + window.scrollY : window.scrollY + viewportPad;
    const sectionWidth = rect ? rect.width : Math.min(window.innerWidth - viewportPad * 2, popupMaxWidth);

    const width = Math.min(sectionWidth * 0.9, popupMaxWidth);
    const left = Math.max(viewportPad, sectionLeft + (sectionWidth - width) / 2);
    const popupMaxHeight = Math.min(800, Math.floor(window.innerHeight * 0.8));
    const topCentered = window.scrollY + Math.max(viewportPad, (window.innerHeight - popupMaxHeight) / 2);

    this.modalStyle = {
      position: 'fixed',
      top: `${Math.floor(topCentered)}px`,
      left: `${Math.floor(left)}px`,
      width: `${Math.floor(width)}px`,
    };

    this.selectedAnnouncement = ann;
    this.showAnnouncementModal = true;

    if (ann.id && !ann.is_read) {
      try {
        await lastValueFrom(this.announcementsService.markAsRead(ann.id));
        // Aggiorna stato locale
        this.annunci = this.annunci.map(a =>
          a.id === ann.id ? { ...a, is_read: true } : a
        );
        if (this.selectedAnnouncement?.id === ann.id) {
          this.selectedAnnouncement.is_read = true;
        }
      } catch (error) {
        console.error('Errore markAsRead', error);
      }
    }
  }

  closeAnnouncement() {
    this.showAnnouncementModal = false;
    this.selectedAnnouncement = null;
    this.modalStyle = {};
  }

  async toggleMarkUnread(ann: AnnouncementWithReadStatus | null) {
    if (!ann?.id) return;
    try {
      if (ann.is_read) {
        await lastValueFrom(this.announcementsService.markAsUnread(ann.id));
        ann.is_read = false;
      } else {
        await lastValueFrom(this.announcementsService.markAsRead(ann.id));
        ann.is_read = true;
      }
      // Aggiorna lista
      this.annunci = this.annunci.map(a =>
        a.id === ann.id ? { ...a, is_read: ann.is_read } : a
      );
      if (this.selectedAnnouncement?.id === ann.id) {
        this.selectedAnnouncement.is_read = ann.is_read;
      }
    } catch (error) {
      console.error('Errore toggle read', error);
    }
  }

  async creaAnnuncio() {
    if (!this.azienda?.id || !this.currentUser) return;

    try {
      const nuovoAnnuncio = await lastValueFrom(
        this.announcementsService.creaAnnuncio(this.azienda.id, {
          title: this.nuovoAnnuncio.title,
          content: this.nuovoAnnuncio.content,
          author_id: this.currentUser.id
        })
      );
      // Aggiungi il flag is_read (l'autore ha già letto)
      const nuovoConStatus: AnnouncementWithReadStatus = {
        ...nuovoAnnuncio,
        is_read: true
      };
      this.annunci = [nuovoConStatus, ...this.annunci];
      this.nuovoAnnuncio = { title: '', content: '' };
      this.mostraFormAnnuncio = false;
    } catch (error) {
      console.error('Errore creazione annuncio', error);
      alert('Errore durante la creazione dell\'annuncio');
    }
  }

  annullaCreazioneAnnuncio() {
    this.mostraFormAnnuncio = false;
    this.nuovoAnnuncio = { title: '', content: '' };
  }

  private async ensureSectionVisible(): Promise<void> {
    const el = this.announcementsSectionRef?.nativeElement;
    if (el) {
      el.scrollIntoView({ behavior: 'smooth', block: 'center' });
      await new Promise(res => setTimeout(res, 300));
    }
  }

  // --- Utility per orari e giorni chiusi ---
  isGiornoChiuso(giornoKey?: string): boolean {
    if (!giornoKey || !this.azienda?.closed_days) return false;
    const closedDays = this.azienda.closed_days;
    if (!Array.isArray(closedDays)) return false;

    return closedDays.some((item: any) => {
      if (!item) return false;
      if (typeof item === 'string' || typeof item === 'number') {
        const s = String(item);
        const datePart = s.split('|')[0];
        if (datePart.includes('/')) {
          const [start, end] = datePart.split('/');
          return giornoKey >= start && giornoKey <= end;
        }
        return datePart === giornoKey;
      }
      if (typeof item === 'object') {
        const type = item.type || (item.start && item.end ? 'range' : 'single');
        if (type === 'single') {
          return item.start === giornoKey;
        }
        if (type === 'range') {
          return item.start && item.end && giornoKey >= item.start && giornoKey <= item.end;
        }
      }
      return false;
    });
  }

  getOrarioGiorno(giornoKey?: string): string {
    if (!giornoKey) return 'Non specificato';
    if (this.isGiornoChiuso(giornoKey)) {
      return 'Chiuso';
    }

    const orari = this.azienda?.opening_hours;
    const giorno = orari?.[giornoKey];

    if (!giorno) {
      if (this.azienda?.opening_time && this.azienda?.closing_time) {
        return `${this.azienda.opening_time} - ${this.azienda.closing_time}`;
      }
      return 'Non specificato';
    }

    if (giorno.closed || !giorno.open || !giorno.close) {
      return 'Chiuso';
    }

    return `${giorno.open} - ${giorno.close}`;
  }

  getRuoloLabel(role?: string | null): string {
    if (!role) return 'Dipendente';
    switch (role) {
      case 'admin': return 'Amministratore';
      case 'manager': return 'Manager';
      case 'employee': return 'Dipendente';
      default: return role.charAt(0).toUpperCase() + role.slice(1);
    }
  }

  hasRole(role: string): boolean {
    return this.authService.hasRole(role);
  }

  getAuthorName(ann: AnnouncementWithReadStatus | null | undefined): string {
    if (!ann?.created_by) return 'Sconosciuto';
    const autore = this.dipendenti.find(d => d.id === ann.created_by);
    return autore ? `${autore.first_name} ${autore.last_name}` : 'Utente sconosciuto';
  }


}
